DROP TABLE IF EXISTS lojas_cinema;
CREATE TABLE lojas_cinema (
  id BIGSERIAL PRIMARY KEY,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  id_pdv TEXT,
  nome_pdv TEXT,
  razao_social TEXT,
  status TEXT,
  endereco TEXT,
  bairro TEXT,
  cidade TEXT,
  uf TEXT,
  responsavel TEXT,
  coordenada_cnpj TEXT,
  latitude TEXT,
  longitude TEXT,
  precisao TEXT,
  rede TEXT,
  bandeira TEXT,
  canal TEXT,
  regiao_desenho TEXT,
  cluster TEXT,
  rota TEXT,
  grupo_clientes TEXT,
  cerca_eletronica TEXT,
  mix TEXT,
  tipo_pdv TEXT,
  nome_shopping TEXT,
  lat_clean NUMERIC,
  lng_clean NUMERIC
);















